import{_ as a,o as r,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"📊 市場情緒日報 — 2026-05-01（週五）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_2026-05-01.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_2026-05-01.md"}'),t={name:"Deep32Q知識庫/市場情緒/市場情緒_2026-05-01.md"};function l(h,e,s,c,n,_){return r(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="📊-市場情緒日報-—-2026-05-01-週五" tabindex="-1">📊 市場情緒日報 — 2026-05-01（週五） <a class="header-anchor" href="#📊-市場情緒日報-—-2026-05-01-週五" aria-label="Permalink to &quot;📊 市場情緒日報 — 2026-05-01（週五）&quot;">​</a></h1><blockquote><p>掃描時間：Gale 指令觸發（Telegram） 資料來源：web_search (Google Search grounding)</p></blockquote><hr><h2 id="🌍-全球財經頭條重點-10-點摘要" tabindex="-1">🌍 全球財經頭條重點（10 點摘要） <a class="header-anchor" href="#🌍-全球財經頭條重點-10-點摘要" aria-label="Permalink to &quot;🌍 全球財經頭條重點（10 點摘要）&quot;">​</a></h2><h3 id="_1-🛢️-油價維持高檔-布蘭特-111、wti-106" tabindex="-1">1. 🛢️ 油價維持高檔，布蘭特 $111、WTI $106 <a class="header-anchor" href="#_1-🛢️-油價維持高檔-布蘭特-111、wti-106" aria-label="Permalink to &quot;1. 🛢️ 油價維持高檔，布蘭特 $111、WTI $106&quot;">​</a></h3><p>5/1 WTI 約 $106/桶，布蘭特約 $111/桶。荷莫茲海峽持續封閉。Al Jazeera 報導：「沒有戰爭結束跡象」。全球原油庫存大量消耗。分析師警告若海峽持續封鎖，油價可能重返 $126 以上。 <em>來源：web_search (fxleaders, Al Jazeera, Economictimes)</em></p><h3 id="_2-🔒-荷莫茲第-63-天封閉-全球能源供應中斷" tabindex="-1">2. 🔒 荷莫茲第 63 天封閉，全球能源供應中斷 <a class="header-anchor" href="#_2-🔒-荷莫茲第-63-天封閉-全球能源供應中斷" aria-label="Permalink to &quot;2. 🔒 荷莫茲第 63 天封閉，全球能源供應中斷&quot;">​</a></h3><p>全球約 25% 海運石油、20% LNG 受阻。伊朗最高領袖哈梅內伊 5/1 強硬表態：宣示對海峽控制權，制定新通行規則。美軍實施雙重封鎖。巴基斯坦調停談判無突破。 <em>來源：web_search (Wikipedia 2026 Strait of Hormuz Crisis)</em></p><h3 id="_3-📈-美股-4-30-創歷史新高-5-1-期貨續漲" tabindex="-1">3. 📈 美股 4/30 創歷史新高，5/1 期貨續漲 <a class="header-anchor" href="#_3-📈-美股-4-30-創歷史新高-5-1-期貨續漲" aria-label="Permalink to &quot;3. 📈 美股 4/30 創歷史新高，5/1 期貨續漲&quot;">​</a></h3><p>S&amp;P 500 收 7,209（+1%，五年最佳月），道瓊 49,652（+1.6%），納斯達克 24,892（創歷史新高）。Alphabet 財報優於預期（+10%），Meta 雖獲利增長但股價大跌 8.7%。 <em>來源：web_search (Morningstar, tastylive, Fidelity)</em></p><h3 id="_4-🇹🇼-台灣-q1-gdp-13-69-創近-39-年新高" tabindex="-1">4. 🇹🇼 台灣 Q1 GDP +13.69% 創近 39 年新高 <a class="header-anchor" href="#_4-🇹🇼-台灣-q1-gdp-13-69-創近-39-年新高" aria-label="Permalink to &quot;4. 🇹🇼 台灣 Q1 GDP +13.69% 創近 39 年新高&quot;">​</a></h3><p>主計總處 4/30 公布概估統計。出口年增 51.10%（AI 高效運算+雲端基建），民間消費實質成長 4.89%（近十季新高）。人均 GDP 預估突破 4 萬美元，超越日本和韓國。 <em>來源：web_search (UDN, 鉅亨網, LINE Today)</em></p><h3 id="_5-📊-台股-5-月展望-震盪後挑戰-41-000" tabindex="-1">5. 📊 台股 5 月展望：震盪後挑戰 41,000 <a class="header-anchor" href="#_5-📊-台股-5-月展望-震盪後挑戰-41-000" aria-label="Permalink to &quot;5. 📊 台股 5 月展望：震盪後挑戰 41,000&quot;">​</a></h3><p>5/1 勞動節休市。4 月月線創史上最強（+7,203 點），市值躍全球第六。五大利多：① Q1 獲利估 1.5 兆 ② 戴維斯雙擊 ③ ETF 資金流入 ④ 520 行情 ⑤ Computex 提前反映。北美雲端巨頭資本支出合計 7,250 億美元，AI 基建進入超級循環。 <em>來源：web_search (CTEE, UDN, MoneyLink)</em></p><h3 id="_6-🥇-金價-4-571-小幅下跌-4-600-為關鍵支撐" tabindex="-1">6. 🥇 金價 $4,571 小幅下跌，$4,600 為關鍵支撐 <a class="header-anchor" href="#_6-🥇-金價-4-571-小幅下跌-4-600-為關鍵支撐" aria-label="Permalink to &quot;6. 🥇 金價 $4,571 小幅下跌，$4,600 為關鍵支撐&quot;">​</a></h3><p>5/1 金價跌至 $4,571.84（-$11.42），週線下跌。年增率仍達 41.13%。$4,600 為關鍵支撐，$4,950 為阻力。LongForecast 預測 5 月均價 $4,582。 <em>來源：web_search (TradingEconomics, DailyForex, LongForecast)</em></p><h3 id="_7-🏛️-聯準會維持利率-3-5-3-75-內部分歧加劇" tabindex="-1">7. 🏛️ 聯準會維持利率 3.5%-3.75%，內部分歧加劇 <a class="header-anchor" href="#_7-🏛️-聯準會維持利率-3-5-3-75-內部分歧加劇" aria-label="Permalink to &quot;7. 🏛️ 聯準會維持利率 3.5%-3.75%，內部分歧加劇&quot;">​</a></h3><p>鮑爾主持的最後一場會議出現罕見分歧。市場重新評估利率走向，放棄今年降息押注，重新定價明年升息可能性。美國 Q1 GDP 成長 2%（低於預期），通膨壓力驟升。 <em>來源：web_search (CNA, 華爾街見聞)</em></p><h3 id="_8-🇹🇼-台灣無人機產業突破-出口額超越去年總和" tabindex="-1">8. 🇹🇼 台灣無人機產業突破：出口額超越去年總和 <a class="header-anchor" href="#_8-🇹🇼-台灣無人機產業突破-出口額超越去年總和" aria-label="Permalink to &quot;8. 🇹🇼 台灣無人機產業突破：出口額超越去年總和&quot;">​</a></h3><p>台灣無人機國家隊已有 267 家業者投入供應鏈，國際訂單破百億元。Q1 無人機出口 1.15 億美元，已超越 2025 年全年總額。 <em>來源：web_search (UDN)</em></p><h3 id="_9-💰-全球債務逼近-350-兆-ai-泡沫隱憂浮現" tabindex="-1">9. 💰 全球債務逼近 $350 兆，AI 泡沫隱憂浮現 <a class="header-anchor" href="#_9-💰-全球債務逼近-350-兆-ai-泡沫隱憂浮現" aria-label="Permalink to &quot;9. 💰 全球債務逼近 $350 兆，AI 泡沫隱憂浮現&quot;">​</a></h3><p>分析師警告全球債務泡沫，總債務接近 $350 兆。美股 AI 相關巨型科技股估值過高，可能重演 2000 年網路泡沫。但 AI 基建資本支出持續攀升。 <em>來源：web_search (DiscoveryAlert, WNG)</em></p><h3 id="_10-🌐-印度-5-4-選舉結果即將公布-市場波動預期升溫" tabindex="-1">10. 🌐 印度 5/4 選舉結果即將公布，市場波動預期升溫 <a class="header-anchor" href="#_10-🌐-印度-5-4-選舉結果即將公布-市場波動預期升溫" aria-label="Permalink to &quot;10. 🌐 印度 5/4 選舉結果即將公布，市場波動預期升溫&quot;">​</a></h3><p>全球關注印度議會選舉結果（5/4 公布），預期增加亞洲市場波動。中東戰事持續、油價高檔亦壓抑新興市場信心。 <em>來源：web_search (Businesstoday)</em></p><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>web_search: WTI $106、布蘭特 $111 | fxleaders, Al Jazeera, Economictimes</li><li>web_search: 荷莫茲第 63 天封閉 | Wikipedia (2026 Strait of Hormuz Crisis)</li><li>web_search: 美股 4/30 創高 | Morningstar, tastylive, Fidelity</li><li>web_search: 台灣 Q1 GDP +13.69% | UDN, 鉅亨網, LINE Today</li><li>web_search: 台股 5 月展望 | CTEE, UDN, MoneyLink</li><li>web_search: 金價 $4,571.84 | TradingEconomics, DailyForex, LongForecast</li><li>web_search: 聯準會維持利率 + 分歧 | CNA, 華爾街見聞</li><li>web_search: 台灣無人機 | UDN</li><li>web_search: 全球債務 $350 兆 | DiscoveryAlert, WNG</li><li>web_search: 印度選舉 5/4 | Businesstoday</li></ol><hr><p><em>報告產出：Dr.32 知識管家 | 模型：local/Qwen3.6-35B-A3B-4bit</em></p>',29)])])}const b=a(t,[["render",l]]);export{m as __pageData,b as default};
